#include <vector>
#include <numeric>

using namespace std;

/**
 * @brief Calculates the degree of each vertex in a graph represented by an adjacency matrix.
 * 
 * @param matrix The adjacency matrix of the undirected graph (n x n).
 * @return vector<int64> A vector where ans[i] is the degree of vertex i.
 */
vector<int64> solve(vector<vector<int64>>& matrix) {
    int n = matrix.size();
    vector<int64> ans(n, 0);

    for (int i = 0; i < n; ++i) {
        int64 degree = 0;
        for (int j = 0; j < n; ++j) {
            // Since matrix[i][j] == 1 indicates an edge, we sum up these entries in row i.
            // Because the problem statement guarantees matrix[i][i] == 0, we don't need to worry about self-loops 
            // being counted twice or once when summing the row.
            if (matrix[i][j] == 1) {
                degree++;
            }
        }
        ans[i] = degree;
    }

    return ans;
}
