    /// <summary>
    /// Calculates the degree of each vertex in a graph represented by an adjacency matrix.
    /// </summary>
    /// <param name="matrix">The n x n adjacency matrix.</param>
    /// <returns>An array where ans[i] is the degree of vertex i.</returns>
    public Array<Int64> solve(Array<Array<Int64>> matrix)
    {
        int n = matrix.Length;
        Array<Int64> ans = new Array<Int64>(n);

        for (int i = 0; i < n; i++)
        {
            int degree = 0;
            for (int j = 0; j < n; j++)
            {
                // matrix[i][j] == 1 means there is an edge between i and j
                // Since matrix[i][i] is guaranteed to be 0, we don't need to worry about self-loops adding 2 to the degree.
                if (matrix[i][j] == 1)
                {
                    degree++;
                }
            }
            ans[i] = (Int64)degree;
        }

        return ans;
    }
